<template>
  <div class="order-detail-wrap">
    <van-nav-bar
      fixed
      placeholder
      title="订单详情"
      left-text="返回"
      left-arrow
      @click-left="$router.push('/order')"
    />
    <van-card
      v-for="item in orderDetail.carts"
      :key="item.cartId"
      class="bg-fff"
      :num="item.buyNum"
      :price="item.price / 100"
      :title="item.masterName"
      :thumb="item.imgUrl"
    />
    <van-cell-group class="mt-10">
      <van-cell title="商品金额" :value="'¥' + orderDetail.totalMoney" />
      <van-cell title="运费" value="¥0.00" />
      <van-cell
        value-class="red f20"
        title="实付"
        :value="'¥' + orderDetail.totalMoney"
      />
    </van-cell-group>
    <van-cell title="" class="info mt-10">
      <div slot="label">
        <p><span class="mr-5">订单编号</span><span>{{orderDetail.orderId}}</span></p>
        <p><span class="mr-5">下单时间</span><span>{{format(orderDetail.createTime)}}</span></p>
      </div>
      <van-button size="mini">复制</van-button>

    </van-cell>
    <van-cell
      v-if="orderDetail.orderStatus === '00'"
      title="订单状态:已取消"
      class="fixed state aic"
    >
      <van-button size="small">重新购买</van-button>
    </van-cell>
    <van-cell
      v-else-if="orderDetail.orderStatus === '01'"
      title="订单状态:已支付"
      class="fixed state"
    >
      <button>取消订单</button>
    </van-cell>
    <van-cell v-else class="fixed state">
      <van-count-down slot="title" :time="countDown" format="mm 分 ss 秒" />
      <button @click="pay">去支付</button>
    </van-cell>
  </div>
</template>

<script>
import $axios from "@/utils/index";
export default {
  data() {
    return {
      orderDetail: {},
    };
  },
  methods: {
    async getDetail() {
      try {
        let res = await $axios.get("order/detail", this.$route.params);
        //   console.log(res)
        if (res.code == 666) {
          this.orderDetail = res.result;
          // console.log(this.orderDetail);
        } else {
          console.log(res.msg);
        }
      } catch (err) {
        console.log(err);
      }
    },
    async pay() {
      try {
        let data = {
          orderId: this.orderDetail.orderId,
          allFee: this.orderDetail.allFee,
        };
        let res = await $axios.post("order/pay", data);
        // console.log(res)
        let query={
            totalMoney: this.orderDetail.totalMoney,
            qrCode:res.result.qrcode,
            createTime:this.orderDetail.createTime,
            orderId:this.orderDetail.orderId
          }
        this.$router.push({
          name: "pay",
          query: query,
        });
      } catch (err) {
        console.log(err);
      }
    },

    format(time){
      time= new Date(time)
      let year=time.getFullYear().toString()
      let month=time.getMonth()<9?'0'+time.getMonth():time.getMonth().toString()
      let day=time.getDay()<10?'0'+time.getDay():time.getDay().toString()
      let hour=time.getHours()<10?'0'+time.getHours():time.getHours().toString()
      let min=time.getMinutes()<10?'0'+time.getMinutes():time.getMinutes().toString()
      let sec=time.getSeconds()<10?'0'+time.getSeconds():time.getSeconds().toString()
      return `${year}-${month}-${day} ${hour}:${min}:${sec}`
    }
  },
  computed:{
      countDown(){
          return 15*60*1000-(Date.now()-this.orderDetail.createTime)
      }
  },
  created() {
    this.getDetail();
  },
};
</script>

<style lang="less">
.order-detail-wrap {
  padding-bottom: 60px;
  .state {
    bottom: 0;
  }
  .van-card {
    margin-top: 0;
  }
  .info{
    .van-cell__title{
      flex: 3;
    }

  }
}
</style>